#include <bits/stdc++.h>
using namespace std;

const int N=1e6+10;

int n,k,sum[30],p[30][30],w[30][30],nxt[30],ars=1;
int cnt,c[30],d[30],f[28][1<<13][2],ones[1<<13];
char s[N],t[N];

int main(){
    scanf("%d%d",&n,&k);
    scanf("%s",s+1);
    scanf("%s",t+1);
    for(int i=1;i<=n;i++){
        p[s[i]-'a'][t[i]-'a']++;
        sum[s[i]-'a']++;
    }
    for(int i=0;i<=26;i++){
        w[i][27]=1e9;
        nxt[i]=27;
        for(int j=0;j<=26;j++){
            w[i][j]=sum[i]-p[i][j]+k*(i!=j);
            if(w[i][j]<w[i][nxt[i]])
                nxt[i]=j;
        }
        d[nxt[i]]++;
    }
    for(int i=0;i<=26;i++)
        if(!d[i]){
            ars=0;
            int x=i;
            while(!d[x]){
                d[nxt[x]]--;
                x=nxt[x];
            }
        }
    for(int i=0;i<=26;i++)
        if(d[i] && i!=nxt[i]){
            cnt++;
            int x=i;
            while(d[x]){
                d[x]--;
                c[x]=cnt;
                x=nxt[x];
            }
        }
    if(!cnt)
        ars=0;
    for(int i=1;i<1<<cnt;i++)
        ones[i]=ones[i-(i&(-i))]+1;
    memset(f,0x3f,sizeof(f));
    f[0][0][0]=0;
    for(int i=0;i<=26;i++)
        for(int S=0;S<1<<cnt;S++)
            for(int fl=0;fl<2;fl++)
                for(int j=0;j<=26;j++){
                    int T=S;
                    if(c[i] && nxt[i]!=j) T|=(1<<c[i]-1);
                    if(c[j] && (nxt[i]!=j || c[i]!=c[j])) T|=(1<<c[j]-1);
                    f[i+1][T][fl || nxt[i]!=j]=min(f[i+1][T][fl || nxt[i]!=j],f[i][S][fl]+w[i][j]);
                }
    int ans=1e9;
    for(int i=0;i<1<<cnt;i++)
        ans=min(ans,f[27][i][ars]+k*(cnt-ones[i]));
    printf("%d",ans);
    return 0;
}
